import '../styles/global.css';
import cjkFontsHref from '../styles/cjk-fonts.css?url';
import Header from '../components/Header.astro';
import Footer from '../components/Footer.astro';
import SEO from '../components/SEO.astro';
import { VisualEditing } from '@sanity/astro/visual-editing';
import { getAlternateUrl, type Lang } from '../lib/navigation';

interface Props {
  title: string;
  description?: string;
  lang?: string;
}

const {
  title,
  description = 'A Chinese-heritage, university-adjacent Christian community in Ithaca, NY.',
  lang = 'en',
} = Astro.props;

const alternateUrl = getAlternateUrl(Astro.url.pathname, lang as Lang);
const absoluteAlternateUrl = new URL(alternateUrl, Astro.site ?? 'https://ficcc.org').href;

const isVisualEditingEnabled =
  import.meta.env.PUBLIC_SANITY_VISUAL_EDITING_ENABLED === 'true';
---

<!doctype html>
<html lang={lang}>
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <SEO title={title} description={description} lang={lang} alternateUrl={absoluteAlternateUrl} />
    <link rel="preconnect" href="https://cdn.sanity.io" crossorigin />
    <link rel="stylesheet" href={cjkFontsHref} media="print" onload="this.media='all'" />
    <noscript><link rel="stylesheet" href={cjkFontsHref} /></noscript>
  </head>
  <body>
    <a href="#main-content" class="skip-to-content">Skip to main content</a>
    <Header lang={lang} langToggleHref={alternateUrl} />
    <slot />
    <Footer lang={lang} />
    {isVisualEditingEnabled && <VisualEditing enabled={true} />}
    <script>
      document.addEventListener('click', (e) => {
        const toggle = (e.target as HTMLElement).closest('.lang-toggle') as HTMLAnchorElement | null;
        if (toggle) {
          const targetLang = toggle.href.includes('/zh') ? 'zh' : 'en';
          document.cookie = 'lang-pref=' + targetLang + ';path=/;max-age=31536000;SameSite=Lax';
        }
      });
    </script>
  </body>
</html>

<style is:global>
  .skip-to-content {
    position: absolute;
    left: -9999px;

import { defineConfig } from 'astro/config';
import sitemap from '@astrojs/sitemap';
import sanity from '@sanity/astro';
import react from '@astrojs/react';
import vercel from '@astrojs/vercel';

export default defineConfig({
  site: 'https://ficcc.org',
  // Astro 5 removed output:'hybrid' — static + adapter is the equivalent,
